SELECT
FROM tb_mbm_user u INNER JOIN tb_mbm_point p ON u.id = p.user_id INNER JOIN tb_mbm_point_cash c ON p.id = c.point_id
ORDER BY c.id DESC LIMIT #{offset}, #{recordSize}

